// caught in other cpp files if chaiscript causes them

#ifdef _MSC_VER
#pragma warning(push)
#pragma warning(disable : 4062 4242 4566 4640 4702 6330 28251)
#endif

#ifdef __GNUC__
#pragma GCC diagnostic push
