// Test for vector of unique_ptr
// This tests that a std::vector<std::unique_ptr<T>> can be registered with chaiscript

#include <chaiscript/chaiscript.hpp>
#include <chaiscript/chaiscript_stdlib.hpp>
#include <chaiscript/dispatchkit/bootstrap_stl.hpp>
#include <vector>
#include <memory>

int main() {
    chaiscript::ChaiScript chai;

    struct Foo {
        int x = 42;
    };

    // This should compile - registering a vector of unique_ptrs
    chai.add(chaiscript::bootstrap::standard_library::vector_type<std::vector<std::unique_ptr<Foo>>>("Foo"));

    return 0;
}

